// 解法 1
void solve(int CASE)
{
	int n; cin >> n;
	string s, t; cin >> s >> t;
	s = ' ' + s, t = ' ' + t;

	var ans = vector<pii>();
	var fan = [&](int l, int r)->void {
		fa(i, l, r)s[i] = s[i] == '0' ? '1' : '0';
		ans.pb({ l,r });
		};
	var fann = [&](const string& s, int l, int r)->string {
		string res = s;
		fa(i, l, r)res[i] = res[i] == '0' ? '1' : '0';
		return res;
		};

	fa(i, 1, n - 4) if (s[i] != t[i]) {
		if (s[i] == s[i + 1])fan(i, i + 1);
		else if (s[i] == s[i + 2])fan(i, i + 2);
		else {
			fan(i + 1, i + 2);
			fan(i, i + 2);
		}
	}

	// 剩下 4 个爆搜解决
	string ns, nt;
	fa(i, n - 3, n)ns.pb(s[i]), nt.pb(t[i]);
	var Q = queue<pair<string, vector<pii>>>();
	Q.push({ ns,{} });
	var se = set<string>();
	while (Q.size()) {
		var[now, res] = Q.front();
		Q.pop();

		if (now == nt) {
			ans.insert(ans.end(), all(res));
			break;
		}

		if (se.count(now))continue;
		se.insert(now);

		var f = [&](int l, int r)->void {
			string to = fann(now, l, r);
			if (se.count(to))return;
			var nres = res;
			nres.pb({ n - 3 + l, n - 3 + r });
			Q.push({ to, nres });
			};

		fa(i, 0, 2)if (now[i] == now[i + 1])f(i, i + 1);
		fa(i, 0, 1)
			if (now[i] == now[i + 1] and now[i + 1] == now[i + 2] or
				now[i] == now[i + 2] and now[i] != now[i + 1])
				f(i, i + 2);
		if (now[0] == now[1] and now[1] == now[2] and now[2] == now[3])
			f(0, 3);
	}

	cout << ans.size() << endl;
	for (const var& [l, r] : ans)cout << l << ' ' << r << endl;
	return;
}

// 解法 2
void solve(int CASE)
{
	int n; cin >> n;
	string s, t; cin >> s >> t;
	s = ' ' + s, t = ' ' + t;

	var anss = vector<pii>();
	var anst = vector<pii>();
	var fans = [&](int l, int r)->void {
		fa(i, l, r)s[i] = s[i] == '0' ? '1' : '0';
		anss.pb({ l,r });
		};
	var fant = [&](int l, int r)->void {
		fa(i, l, r)t[i] = t[i] == '0' ? '1' : '0';
		anst.pb({ l,r });
		};

	fa(i, 1, n) if (s[i] == '1') {
		if (i <= n - 2) {
			if (s[i + 1] == '1')fans(i, i + 1);
			else if (s[i + 2] == '1')fans(i, i + 2);
			else {
              	// 优化总操作数，防止每个 i 都操作两遍
				int j = i + 2;
				while (j + 1 <= n and s[j + 1] == '0')j++;
				fans(i + 1, j);
				fans(i, min(n, j + 1));
			}
		}
		else {
			if (i + 1 <= n and s[i] == s[i + 1])fans(i, i + 1);
			else {
              	// 向前借 2 位
				fans(i - 2, i - 1);
				fans(i - 2, i);
			}
		}
	}
	fa(i, 1, n) if (t[i] == '1') {
		if (i <= n - 2) {
			if (t[i + 1] == '1')fant(i, i + 1);
			else if (t[i + 2] == '1')fant(i, i + 2);
			else {
              	// 优化总操作数，防止每个 i 都操作两遍
				int j = i + 2;
				while (j + 1 <= n and t[j + 1] == '0')j++;
				fant(i + 1, j);
				fant(i, min(n, j + 1));
			}
		}
		else {
			if (i + 1 <= n and t[i] == t[i + 1])fant(i, i + 1);
			else {
              	// 向前借 2 位
				fant(i - 2, i - 1);
				fant(i - 2, i);
			}
		}
	}

	cout << anss.size() + anst.size() << endl;
	for (const var& [l, r] : anss)cout << l << ' ' << r << endl;
	reverse(all(anst));
	for (const var& [l, r] : anst)cout << l << ' ' << r << endl;
	return;
}
